import { useState, useEffect } from "react";
import { Navbar, Nav, Container } from "react-bootstrap";
import { useMediaQuery } from "react-responsive";
import Toggle from "react-toggle";
import "react-toggle/style.css"
import { DarkModeSwitch } from 'react-toggle-dark-mode';
// var Toggle = require('react-toggle')

import { LinkContainer } from "react-router-bootstrap";
import logo from '../assets/img/logo.png';
import navInstagram from '../assets/img/logo-instagram.svg';
import navTwitter from '../assets/img/logo-twitter.svg';
import navGitHub from '../assets/img/logo-octocat.svg';
import navLinkedIn from '../assets/img/logo-linkedin.svg';
import Pdf from '../assets/pdf/Pyo_Jiyoon_CV.pdf';

// import { HashLink } from 'react-router-hash-link';
import {
  BrowserRouter as Router
} from "react-router-dom";

export const NavBar = () => {
  const [activeLink, setActiveLink] = useState('home');
  const [scrolled, setScrolled] = useState(false);
  const [isDark, setIsDark] = useState(false);

  const systemPrefersDark = useMediaQuery(
    {
      query: "(prefers-color-scheme: dark)",
    },
    undefined,
    (isSystemDark) => {
      setIsDark(isSystemDark);
      setIsDark(localStorage.getItem("dark"));
    },
  );

  const toggleDarkMode = (checked) => {
    setIsDark(checked);
    localStorage.setItem("dark", checked);
  };

  useEffect(() => {
    if (isDark) {
      document.body.classList.add('dark');
      // console.log(localStorage.getItem('dark', isDark));
    } else {
      document.body.classList.remove('dark');
    };
  }, [isDark]); 

  useEffect(() => {
    const onScroll = () => {
      if (window.scrollY > 50) {
        setScrolled(true);
      } else {
        setScrolled(false);
      }
    }

    window.addEventListener("scroll", onScroll);

    return () => window.removeEventListener("scroll", onScroll);
  }, [])

  const onUpdateActiveLink = (value) => {
    setActiveLink(value);
  };

  return (
    <Router>
      <Navbar expand="md" className={scrolled ? "scrolled" : ""}>
        <Container>
          <Navbar.Brand href="/">
            <h5><img src={logo} height="40px" alt="Logo" /> <b>YOO.uN</b></h5>
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav">
            <span className="navbar-toggler-icon"></span>
          </Navbar.Toggle>
          <Navbar.Collapse id="basic-navbar-nav">
            <Nav className="ms-auto">
              <Nav.Link href="#home" className={activeLink === 'home' ? 'active navbar-link' : 'navbar-link'} onClick={() => onUpdateActiveLink('home')}>Home</Nav.Link>
              <Nav.Link href="#about" className={activeLink === 'about' ? 'active navbar-link' : 'navbar-link'} onClick={() => onUpdateActiveLink('about')}>About Me</Nav.Link>
              {/* <Nav.Link href="#projects" className={activeLink === 'projects' ? 'active navbar-link' : 'navbar-link'} onClick={() => onUpdateActiveLink('projects')}>Projects</Nav.Link> */}
              <Nav.Link href={Pdf} without rel="noopener noreferrer" target="_blank" className={activeLink === 'CV' ? 'active navbar-link' : 'navbar-link'} onClick={() => onUpdateActiveLink('CV')}>CV</Nav.Link>
            </Nav>
            <span className="navbar-text">
              <div className="social-icon">
                {/* <a href="https://www.instagram.com/yoo.un_ee/"><img src={navInstagram} alt=""/></a>
                <a href="https://twitter.com/yoo_un_ee"><img src={navTwitter} alt="" /></a> */}
                <a href="https://www.linkedin.com/in/yoo-un-ee/"><img src={navLinkedIn} alt="" /></a>
                <a href="https://github.com/YOO-uN-ee"><img src={navGitHub} alt="" /></a>
              </div>

              <DarkModeSwitch
                    style={{ marginBottom: '0.7rem' }}
                    checked={isDark}
                    onChange={toggleDarkMode}
                    size={20}
                    moonColor="black"
                    sunColor="white"
                    className="social-icon"
              />
              {/* <HashLink to='#connect'>
                <button className="vvd"><span>Let’s Connect</span></button>
              </HashLink> */}
            </span>
          </Navbar.Collapse>
        </Container>
      </Navbar>
    </Router>
  )
}

export default NavBar;